// // This module detects when the input signal changes from low to high or vice versa.
module zero_crossing_detector (
    input wire clk,
    input wire signal_in,
    output reg zero_cross
);
    reg signal_prev;

    always @(posedge clk) begin
        zero_cross <= (signal_in ^ signal_prev) && signal_prev != signal_in;
        signal_prev <= signal_in;
    end
endmodule
